#include<bits/stdc++.h>
using namespace std;
int t;
int main(){
    cin>>t;
    while(t--){
    int n,p,q,w[1001],v[1001],dp[100000]={0};
    cin>>n>>p>>q;
	for(int i=1;i<=n;i++){
		cin>>v[i]>>w[i];
	}
	for(int i=1;i<=n;i++){
		for(int j=q;j>=w[i];j--){
			dp[j]=max(dp[j],dp[j-w[i]]+v[i]);
		}
	}bool flag = true;
		for (int i = 1; i <= q; i++) {
			if (dp[i] >= p) {
				cout << i << endl;
				flag = false;
				break;
			}
		}
		if (flag)
			cout << -1 << endl;}
    return 0;
}
